import{_ as e,o as l,c as s,ai as i}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"聊天渠道","description":"","frontmatter":{"read_when":["你想为 OpenSoul 选择一个聊天渠道","你需要快速了解支持的消息平台"],"summary":"OpenSoul 可连接的消息平台","title":"聊天渠道","x-i18n":{"generated_at":"2026-02-03T07:43:27Z","model":"claude-opus-4-5","provider":"pi","source_hash":"2632863def6dee97e0fa8b931762f0969174fd4fb22303a00dcd46527fe4a141","source_path":"channels/index.md","workflow":15}},"headers":[],"relativePath":"zh-CN/channels/index.md","filePath":"zh-CN/channels/index.md","lastUpdated":null}'),o={name:"zh-CN/channels/index.md"};function n(c,a,r,h,t,d){return l(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="聊天渠道" tabindex="-1"><a class="header-anchor" href="#聊天渠道">#</a> 聊天渠道</h1><p>OpenSoul 可以在你已经使用的任何聊天应用上与你交流。每个渠道通过 Gateway 网关连接。 所有渠道都支持文本；媒体和表情回应的支持因渠道而异。</p><h2 id="支持的渠道" tabindex="-1"><a class="header-anchor" href="#支持的渠道">#</a> 支持的渠道</h2><ul><li><a href="/docs/channels/whatsapp">WhatsApp</a> — 最受欢迎；使用 Baileys，需要二维码配对。</li><li><a href="/docs/channels/telegram">Telegram</a> — 通过 grammY 使用 Bot API；支持群组。</li><li><a href="/docs/channels/discord">Discord</a> — Discord Bot API + Gateway；支持服务器、频道和私信。</li><li><a href="/docs/channels/slack">Slack</a> — Bolt SDK；工作区应用。</li><li><a href="/docs/channels/feishu">飞书</a> — 飞书（Lark）机器人（插件，需单独安装）。</li><li><a href="/docs/channels/googlechat">Google Chat</a> — 通过 HTTP webhook 的 Google Chat API 应用。</li><li><a href="/docs/channels/mattermost">Mattermost</a> — Bot API + WebSocket；频道、群组、私信（插件，需单独安装）。</li><li><a href="/docs/channels/signal">Signal</a> — signal-cli；注重隐私。</li><li><a href="/docs/channels/bluebubbles">BlueBubbles</a> — <strong>推荐用于 iMessage</strong>；使用 BlueBubbles macOS 服务器 REST API，功能完整（编辑、撤回、特效、回应、群组管理——编辑功能在 macOS 26 Tahoe 上目前不可用）。</li><li><a href="/docs/channels/imessage">iMessage（旧版）</a> — 通过 imsg CLI 的旧版 macOS 集成（已弃用，新设置请使用 BlueBubbles）。</li><li><a href="/docs/channels/msteams">Microsoft Teams</a> — Bot Framework；企业支持（插件，需单独安装）。</li><li><a href="/docs/channels/line">LINE</a> — LINE Messaging API 机器人（插件，需单独安装）。</li><li><a href="/docs/channels/nextcloud-talk">Nextcloud Talk</a> — 通过 Nextcloud Talk 的自托管聊天（插件，需单独安装）。</li><li><a href="/docs/channels/matrix">Matrix</a> — Matrix 协议（插件，需单独安装）。</li><li><a href="/docs/channels/nostr">Nostr</a> — 通过 NIP-04 的去中心化私信（插件，需单独安装）。</li><li><a href="/docs/channels/tlon">Tlon</a> — 基于 Urbit 的消息应用（插件，需单独安装）。</li><li><a href="/docs/channels/twitch">Twitch</a> — 通过 IRC 连接的 Twitch 聊天（插件，需单独安装）。</li><li><a href="/docs/channels/zalo">Zalo</a> — Zalo Bot API；越南流行的消息应用（插件，需单独安装）。</li><li><a href="/docs/channels/zalouser">Zalo Personal</a> — 通过二维码登录的 Zalo 个人账号（插件，需单独安装）。</li><li><a href="/docs/web/webchat">WebChat</a> — 基于 WebSocket 的 Gateway 网关 WebChat 界面。</li></ul><h2 id="注意事项" tabindex="-1"><a class="header-anchor" href="#注意事项">#</a> 注意事项</h2><ul><li>渠道可以同时运行；配置多个渠道后，OpenSoul 会按聊天进行路由。</li><li>最快的设置方式通常是 <strong>Telegram</strong>（简单的机器人令牌）。WhatsApp 需要二维码配对， 并在磁盘上存储更多状态。</li><li>群组行为因渠道而异；参见<a href="/docs/channels/groups">群组</a>。</li><li>为安全起见，私信配对和允许列表会被强制执行；参见<a href="/docs/gateway/security/index">安全</a>。</li><li>Telegram 内部机制：<a href="/docs/channels/grammy">grammY 说明</a>。</li><li>故障排除：<a href="/docs/channels/troubleshooting">渠道故障排除</a>。</li><li>模型提供商单独记录；参见<a href="/docs/providers/models">模型提供商</a>。</li></ul>',6)])])}const u=e(o,[["render",n]]);export{m as __pageData,u as default};
